// statusLine is the first-paint status sentence for the updates card,
// derived from the coordinator phase baked into the page. The SSE
// handler overwrites it live after load.
func statusLine(d SystemPageData) string {
	switch d.Phase {
	case "downloading":
		return "Downloading…"
	case "up-to-date":
		return "You are on the latest version."
	case "staged":
		if d.StagedVersion != "" {
			return d.StagedVersion + " is ready to apply."
		}
		return "A new version is ready to apply."
	case "applying":
		return "Applying update…"
	case "error":
		if d.Error != "" {
			return "Update failed: " + d.Error
		}
		return "Update failed."
	}
	if d.HasStaged {
		if d.StagedVersion != "" {
			return d.StagedVersion + " is ready to apply."
		}
		return "A new version is ready to apply."
	}
	return "Click “Check for updates” to look for a new release."
}

